    "parameters": {
      "type": "object",
      "properties": {
        "report_id": {
          "type": "string",
          "description": "The unique identifier for the expense report (e.g., 'EXP-2024-V2')."
        }
      },
      "required": [
        "report_id"
      ]
    },
    "example_output": {
      "report_id": "EXP-2024-V2",
      "submitter_id": "EMP-992",
      "project_id": "PROJ-ABC",
      "line_items": [
        {
          "id": "LI-001",
          "amount": 150.0,
          "category": "Travel",
          "is_billable": true
        }
      ]
    }
  },
  "fetch_project_sow_terms": {
    "description": "Retrieves the governing SOW terms for a project, including allowable expense categories and the remaining Not-to-Exceed (NTE) balance.",
    "parameters": {
      "type": "object",
      "properties": {
        "project_id": {
          "type": "string",
          "description": "The unique identifier for the project."
        }
      },
      "required": [
        "project_id"
      ]
    },
    "example_output": {
      "nte_balance": 5000.0,
      "allowable_categories": [
        "Travel",
        "Meals",
        "Software"
      ],
      "currency": "USD"
    }
  },
  "fetch_employee_metadata": {
    "description": "Retrieves administrative data for an employee, specifically their department's variance account for non-compliant cost re-routing.",
    "parameters": {
      "type": "object",
      "properties": {
        "employee_id": {
          "type": "string",
          "description": "The unique identifier for the employee."
        }
      },
      "required": [
        "employee_id"
      ]
    },
    "example_output": {
      "department_id": "DEPT-FIN",
      "variance_account_id": "VAR-ACC-FIN-01"
    }
  },
  "reallocate_line_item": {
    "description": "Updates a specific line item's billing status and routes the cost to a specific account (e.g., a variance account).",
    "parameters": {
      "type": "object",
      "properties": {
        "report_id": {
          "type": "string",
          "description": "The report ID containing the line item."
        },
        "item_id": {
          "type": "string",
          "description": "The ID of the specific line item to adjust."
        },
        "is_billable": {
          "type": "boolean",
          "description": "Whether the item is billable to the project project."
        },
        "destination_account_id": {
          "type": "string",
          "description": "The account ID where the cost should be routed (e.g., the variance account)."
        }
      },
      "required": [
        "report_id",
        "item_id",
        "is_billable",
        "destination_account_id"
      ]
    },
    "example_output": {
      "success": true,
      "updated_item": "LI-001"
    }
  },
  "submit_final_audit": {
    "description": "Finalizes the audit process and transitions the report status.",
    "parameters": {
      "type": "object",
      "properties": {
        "report_id": {
          "type": "string",
          "description": "The ID of the report to finalize."
        },
        "status": {
          "type": "string",
          "enum": [
            "Approved",
            "Rejected"
          ],
          "description": "The final status to set for the report."
        },
        "audit_note": {
          "type": "string",
          "description": "A summary of the adjustments made."
        }
      },
      "required": [
        "report_id",
        "status"
      ]
    },
    "example_output": {
      "report_id": "EXP-2024-V2",
      "final_status": "Approved"
    }
  }
